 16	type SnapshotActionsMenuProps = {
 17	  isRestoreDisabled: boolean;
 18	  snapshot: V1beta1VirtualMachineSnapshot;
 19	};
 20	
 21	const SnapshotActionsMenu: FC<SnapshotActionsMenuProps> = ({ isRestoreDisabled, snapshot }) => {
 22	  const { t } = useKubevirtTranslation();
 23	  const { createModal } = useModal();
 24	  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
 25	
 26	  const [canClone] = useAccessReview({
 27	    group: VirtualMachineCloneModel.apiGroup,
 28	    namespace: snapshot.metadata.namespace,
 29	    resource: VirtualMachineCloneModel.plural,
 30	    verb: 'create',
 31	  });
 32	
 33	  const deleteLabel = t('Delete snapshot');
 34	
 35	  const onRestoreModalToggle = useCallback(() => {
 36	    createModal(({ isOpen, onClose }) => (
 37	      <RestoreModal isOpen={isOpen} onClose={onClose} snapshot={snapshot} />
 38	    ));
 39	    setIsDropdownOpen(false);
 40	  }, [createModal, snapshot]);
 41	
 42	  const onClone = useCallback(() => {
 43	    createModal(({ isOpen, onClose }) => (
 44	      <CloneVMModal
 45	        headerText={t('Create VirtualMachine from snapshot')}
 46	        isOpen={isOpen}
 47	        onClose={onClose}
 48	        source={snapshot}
 49	      />
 50	    ));
 51	    setIsDropdownOpen(false);
 52	  }, [createModal, snapshot, t]);
 53	
 54	  const onDeleteModalToggle = useCallback(() => {
 55	    createModal(({ isOpen, onClose }) => (
 56	      <TabModal<V1beta1VirtualMachineSnapshot>
 57	        onSubmit={(obj) =>
 58	          k8sDelete({
 59	            model: VirtualMachineSnapshotModel,
 60	            resource: obj,
 61	          })
 62	        }
 63	        headerText={t('Delete VirtualMachineSnapshot?')}
 64	        isOpen={isOpen}
 65	        obj={snapshot}
 66	        onClose={onClose}
 67	        submitBtnText={deleteLabel}
 68	        submitBtnVariant={ButtonVariant.danger}
 69	      >
 70	        <ConfirmActionMessage obj={snapshot} />
 71	      </TabModal>
 72	    ));
 73	    setIsDropdownOpen(false);
 74	  }, [createModal, deleteLabel, snapshot, t]);
 75	
 76	  const onToggle = () => setIsDropdownOpen((prevIsOpen) => !prevIsOpen);
 77	
 78	  return (
 79	    <Dropdown
 80	      isOpen={isDropdownOpen}
 81	      onSelect={() => setIsDropdownOpen(false)}
 82	      popperProps={{ position: 'right' }}
 83	      toggle={KebabToggle({ id: 'toggle-id-6', isExpanded: isDropdownOpen, onClick: onToggle })}
 84	    >
 85	      <DropdownList>
 86	        <DropdownItem
 87	          description={t('Create a copy of the VirtualMachine from snapshot')}
 88	          isDisabled={!canClone}
 89	          key="snapshot-clone"
 90	          onClick={onClone}
 91	        >
 92	          {t('Create VirtualMachine')}
 93	        </DropdownItem>
 94	        <DropdownItem
 95	          description={t('Restore the VirtualMachine to this snapshot`s state')}
 96	          isDisabled={isRestoreDisabled}
 97	          key="snapshot-restore"
 98	          onClick={onRestoreModalToggle}
 99	        >
100	          {t('Restore VirtualMachine from snapshot')}
101	        </DropdownItem>
102	        <DropdownItem key="snapshot-delete" onClick={onDeleteModalToggle}>
103	          {deleteLabel}
104	        </DropdownItem>
105	      </DropdownList>
106	    </Dropdown>
107	  );
108	};
109	
110	export default SnapshotActionsMenu;

